import { useEffect, useMemo, useRef, useState } from "react";

// Define los colores para fácil acceso
const navy = '#072d42';
const beige = '#F4E9D7';

export default function Index() {
  const sections = useMemo(
    () => [
      {
        id: "objective",
        title: "Objective",
        body: (
          <p style={{ color: navy, opacity: 0.9 }}>
            Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian
            companies with more than 40 years of trajectory. We digitize archives, certify milestones,
            and curate living narratives that honor legacy while inspiring the next generation of leaders.
          </p>
        ),
      },
      {
        id: "mission",
        title: "Mission",
        body: (
          <p style={{ color: navy, opacity: 0.9 }}>
            To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful
            storytelling, and timeless design—making each company’s journey accessible, verifiable, and
            beautifully preserved for the future.
          </p>
        ),
      },
      {
        id: "vision",
        title: "Vision",
        body: (
          <p style={{ color: navy, opacity: 0.9 }}>
            A prestigious national archive where the history of business excellence is treasured—
            a reference for researchers, entrepreneurs, and families that elevates the legacy of
            Bolivian industry on the world stage.
          </p>
        ),
      },
      {
        id: "origin",
        title: "Origin",
        body: (
          <p style={{ color: navy, opacity: 0.9 }}>
            Born from a commitment to cultural memory, Orbis Empresarial emerged when historians,
            archivists, and innovators united around a single idea: if we don’t document our
            enterprises today, tomorrow’s generations will inherit silence where there should be legacy.
          </p>
        ),
      },
      {
        id: "how",
        title: "How it started",
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div
                className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-[3px] rounded-full"
                style={{ background: `linear-gradient(to right, ${beige}, ${navy})` }}
              />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {[
                  { year: "1980s", text: "Foundational archives collected across departments." },
                  { year: "1990s", text: "First private–public preservation partnerships." },
                  { year: "2000s", text: "Digitization program and certification standards." },
                  { year: "2010s", text: "Interactive exhibits and institutional expansion." },
                  { year: "Today", text: "A living platform connecting legacy with innovation." },
                ].map((m) => (
                  <li key={m.year} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <span className="block w-3 h-3 rounded-full" style={{ backgroundColor: navy, boxShadow: `0 0 0 6px ${navy}33` }} />
                      </div>
                      <div className="text-sm font-medium tracking-wide" style={{color: navy}}>
                        <span className="font-serif-display text-xl block">{m.year}</span>
                        <span className="block max-w-[16rem]" style={{ color: navy, opacity: 0.8 }}>{m.text}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [],
  );

  const [active, setActive] = useState(sections[0].id);
  const [visible, setVisible] = useState({});
  const refs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        let best = { id: active, ratio: 0 };
        entries.forEach((entry) => {
          const id = entry.target.id;
          if (entry.isIntersecting) {
            setVisible((prev) => ({ ...prev, [id]: true }));
          }
          if (entry.intersectionRatio > best.ratio) {
            best = { id, ratio: entry.intersectionRatio };
          }
        });
        if (best.id) setActive(best.id);
      },
      { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: "-20% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = refs.current[s.id];
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, []);

  const scrollTo = (id) => {
    const el = refs.current[id];
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };
  
  const activeButtonStyle = { color: navy, ring: '1px solid #072d42' };
  const inactiveButtonStyle = { color: navy, opacity: 0.8 };

  return (
    <div style={{ backgroundColor: beige, color: navy }}>
      <main className="mx-auto max-w-[1400px] px-4 sm:px-6 lg:px-10 py-6 sm:py-10">
        <div className="md:hidden sticky top-0 z-20 -mx-4 px-4 py-3 backdrop-blur" style={{ backgroundColor: `${beige}b3`, borderColor: `${navy}80` }}>
          <div className="flex gap-3 overflow-x-auto no-scrollbar">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={() => scrollTo(s.id)}
                className="whitespace-nowrap rounded-full px-4 py-2 text-sm tracking-wide transition relative"
                style={active === s.id ? activeButtonStyle : inactiveButtonStyle}
              >
                {s.title}
              </button>
            ))}
          </div>
        </div>

        <div className="grid md:grid-cols-[minmax(220px,18%)_1fr] gap-6 lg:gap-10">
          <aside className="hidden md:flex sticky top-6 h-[calc(100vh-3rem)] flex-col justify-between border-r pr-6 lg:pr-8" style={{ borderColor: `${navy}99` }}>
            <div>
              <h1 className="font-serif-display text-3xl lg:text-4xl tracking-tight" style={{ color: navy }}>
                Orbis Empresarial
              </h1>
              <div className="mt-2 h-[3px] w-16 rounded-full" style={{ backgroundColor: navy }} />
              <p className="mt-4 text-sm" style={{ color: navy, opacity: 0.9 }}>
                Preserving the living history of Bolivian companies 40+ years strong.
              </p>

              <nav className="mt-8 flex flex-col gap-2">
                {sections.map((s) => (
                  <button
                    key={s.id}
                    onClick={() => scrollTo(s.id)}
                    className="group text-left px-3 py-2 rounded-md transition relative"
                    style={active === s.id ? {color: navy, backgroundColor: `${navy}1a`, ring: '1px solid #072d4266'} : {color: navy, opacity: 0.8}}
                  >
                    <span className="inline-flex items-center gap-3">
                      <span
                        className={`inline-block h-1.5 w-1.5 rounded-full transition-all ${active === s.id ? 'scale-100' : 'scale-75'}`}
                        style={{ backgroundColor: active === s.id ? navy : `${navy}b3` }}
                      />
                      <span className="uppercase tracking-wider text-xs lg:text-sm">
                        {s.title}
                      </span>
                    </span>
                  </button>
                ))}
              </nav>
            </div>

            <div className="hidden lg:block text-xs" style={{ color: navy, opacity: 0.7 }}>
              © {new Date().getFullYear()} Orbis Empresarial
            </div>
          </aside>

          <section className="flex flex-col gap-8 lg:gap-12">
            {sections.map((s, idx) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (refs.current[s.id] = el)}
                className="scroll-mt-28 md:scroll-mt-14"
              >
                <div
                  className={`group relative rounded-2xl p-[1px] transition-transform duration-300 ${
                    visible[s.id] ? "translate-y-0 opacity-100" : "translate-y-6 opacity-0"
                  }`}
                  style={{ transitionProperty: "transform, opacity" }}
                >
                  <div className="rounded-2xl" style={{ background: `linear-gradient(to bottom right, ${beige}, ${navy}59)` }}>
                    <div className="relative rounded-2xl p-6 sm:p-8 lg:p-12 shadow-[0_10px_30px_rgba(7,45,66,0.15)]" style={{backgroundColor: `${beige}b3`, backdropFilter: 'blur(24px)'}}>
                      <header className="mb-4 sm:mb-6">
                        <h2 className="font-serif-display text-2xl sm:text-3xl lg:text-4xl" style={{ color: navy }}>
                          {s.title}
                        </h2>
                        <div className="mt-2 h-[3px] w-14 rounded-full transition-all group-hover:w-20" style={{ backgroundColor: navy }} />
                      </header>
                      <div className="prose prose-neutral max-w-none text-base sm:text-lg" style={{ color: navy, opacity: 0.9 }}>
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>

                {idx !== sections.length - 1 && (
                  <div className="mt-8 h-px" style={{ background: `linear-gradient(to right, transparent, ${navy}b3, transparent)` }} />
                )}
              </div>
            ))}
          </section>
        </div>
      </main>
    </div>
  );
}
